// CancelPayment is the resolver for the cancelPayment field.
func (r *mutationResolver) CancelPayment(ctx context.Context, id string, reason string) (*model.MutationResponse, error) {
	// Solo ADMIN puede cancelar pagos
	if err := middleware.MustBeAdmin(ctx); err != nil {
		return nil, err
	}
	paymentID, err := parseID(id)
	if err != nil {
		return nil, err
	}

	// 1) obtener el pago
	existing, err := r.paymentService.GetPayment(ctx, paymentID)
	if err != nil {
		return nil, err // Retornar el error directamente
	}
	if existing == nil {
		return nil, appErrors.NewNotFoundError("Payment") // Retornar error not found
	}

	// 2) si ya está cancelado, devuelves error o idempotencia
	if existing.Status == models.PaymentStatusCancelled {
		return &model.MutationResponse{
			Success: false,
			Error:   stringPtr("Payment is already cancelled"),
		}, nil
	}

	// 3) llamar a un método de tu servicio
	if err := r.paymentService.CancelPayment(ctx, paymentID, reason); err != nil {
		errMsg := err.Error()
		return &model.MutationResponse{Success: false, Error: &errMsg}, err
	}

	// 4) devolver éxito
	msg := "Payment cancelled successfully"
	return &model.MutationResponse{Success: true, Message: &msg}, nil
}

