// RegisterFee is the resolver for the registerFee field.
func (r *mutationResolver) RegisterFee(ctx context.Context, year int, baseAmount float64) (*model.MutationResponse, error) {
	// Solo ADMIN puede registrar cuotas
	if err := middleware.MustBeAdmin(ctx); err != nil {
		return nil, err
	}
	// Validación básica de los parámetros
	if year < 2000 || year > 2100 {
		return nil, appErrors.NewValidationError(
			"Invalid year",
			map[string]string{"year": "Year must be between 2000 and 2100"},
		)
	}

	if baseAmount <= 0 {
		return nil, appErrors.NewValidationError(
			"Invalid base amount",
			map[string]string{"baseAmount": "Base amount must be greater than zero"},
		)
	}

	// 1) Crear la cuota de membresía anual para ese año en la BD
	err := r.paymentService.GenerateAnnualFee(ctx, year, baseAmount)
	if err != nil {
		return nil, err
	}

	// 2) Devolver un mensaje confirmando la operación
	msg := fmt.Sprintf("Membership fee for year %d has been generated successfully", year)
	return &model.MutationResponse{
		Success: true,
		Message: &msg,
	}, nil
}

// GenerateAnnualFees is the resolver for the generateAnnualFees field.
func (r *mutationResolver) GenerateAnnualFees(ctx context.Context, input model.GenerateAnnualFeesInput) (*model.GenerateAnnualFeesResponse, error) {
	// Solo ADMIN puede generar cuotas anuales
	if err := middleware.MustBeAdmin(ctx); err != nil {
		return nil, err
	}

	// Convertir input GraphQL a request del servicio
	req := &inputPorts.GenerateAnnualFeesRequest{
		Year:           input.Year,
		BaseFeeAmount:  input.BaseFeeAmount,
		FamilyFeeExtra: input.FamilyFeeExtra,
	}

	// Llamar al servicio
	result, err := r.paymentService.GenerateAnnualFees(ctx, req)
	if err != nil {
		return nil, err
	}

	// Convertir response del servicio a GraphQL
	response := &model.GenerateAnnualFeesResponse{
		Year:                result.Year,
		MembershipFeeID:     fmt.Sprintf("%d", result.MembershipFeeID),
		PaymentsGenerated:   result.PaymentsGenerated,
		PaymentsExisting:    result.PaymentsExisting,
		TotalMembers:        result.TotalMembers,
		TotalExpectedAmount: result.TotalExpectedAmount,
		Details:             make([]*model.PaymentGenerationDetail, len(result.Details)),
	}

	// Convertir detalles
	for i, detail := range result.Details {
		errorMsg := detail.Error
		response.Details[i] = &model.PaymentGenerationDetail{
			MemberID:     fmt.Sprintf("%d", detail.MemberID),
			MemberNumber: detail.MemberNumber,
			MemberName:   detail.MemberName,
			Amount:       detail.Amount,
			WasCreated:   detail.WasCreated,
			Error:        &errorMsg,
		}
	}

	return response, nil
}

