// GetTransactions is the resolver for the getTransactions field.
func (r *queryResolver) GetTransactions(ctx context.Context, filter *model.TransactionFilter) (*model.TransactionConnection, error) {
	// Verificar autenticación
	if err := middleware.MustBeAuthenticated(ctx); err != nil {
		return nil, err
	}

	// Obtener MemberID del contexto (nil para admin, memberID para user)
	memberID, err := middleware.GetMemberIDFromContext(ctx)
	if err != nil {
		return nil, err
	}

	page := 1
	pageSize := 10
	var orderBy string
	var startDate, endDate *time.Time
	var operationType *models.OperationType
	var filterMemberID *uint

	if filter != nil {
		if filter.Pagination != nil {
			page = filter.Pagination.Page
			pageSize = filter.Pagination.PageSize
		}
		if filter.Sort != nil {
			orderBy = fmt.Sprintf("%s %s", filter.Sort.Field, filter.Sort.Direction)
		}
		if filter.StartDate != nil {
			startDate = filter.StartDate
		}
		if filter.EndDate != nil {
			endDate = filter.EndDate
		}
		if filter.OperationType != nil {
			op := *filter.OperationType
			operationType = &op
		}
		// Si viene memberID en el filtro (solo admin puede usarlo)
		if filter.MemberID != nil {
			parsedID, err := parseID(*filter.MemberID)
			if err == nil {
				filterMemberID = &parsedID
			}
		}
	}

	// Si el usuario es USER (no admin), forzar el filtro por su memberID
	if memberID != nil {
		filterMemberID = memberID
	}

	cfFilter := inputPorts.CashFlowFilter{
		StartDate:     startDate,
		EndDate:       endDate,
		OperationType: operationType,
		MemberID:      filterMemberID,
		Page:          page,
		PageSize:      pageSize,
		OrderBy:       orderBy,
	}

	// Llamar al servicio
	movements, err := r.cashFlowService.GetMovementsByPeriod(ctx, cfFilter)
	if err != nil {
		return nil, err
	}

	// Construir PageInfo, con paginación "incompleta" (no tenemos total real)
	pageInfo := &model.PageInfo{
		HasNextPage:     false, // sin total real, no sabemos si hay más
		HasPreviousPage: page > 1,
		TotalCount:      len(movements), // no es el total global, solo la página actual
	}

	return &model.TransactionConnection{
		Nodes:    movements,
		PageInfo: pageInfo,
	}, nil
}

// GetBalance is the resolver for the getBalance field.
func (r *queryResolver) GetBalance(ctx context.Context) (float64, error) {
	// Solo ADMIN puede ver el balance general
	if err := middleware.MustBeAdmin(ctx); err != nil {
		return 0, err
	}

	// 1) Llamas a un método de tu servicio (p. ej. "GetCurrentBalance")
	balance, err := r.cashFlowService.GetCurrentBalance(ctx)
	if err != nil {
		return 0, err
	}

	// 2) Retornas el valor numérico
	return balance.CurrentBalance, nil
}

